/**
 * UMI-OS Synth Simulator - Self-contained AudioWorklet
 * 
 * This worklet contains the full UMI-OS kernel simulation including:
 * - Task Scheduler (4 priority levels)
 * - MIDI processing (sample-accurate)
 * - Audio processing
 * - Memory management simulation
 * - Watchdog timer
 * 
 * The WASM binary is embedded as base64 for AudioWorklet compatibility.
 */

// Base64-encoded WASM binary (will be appended)
const WASM_BASE64 = "";

class UmiSynthSimProcessor extends AudioWorkletProcessor {
    constructor(options) {
        super();
        
        this.wasmModule = null;
        this.wasmInstance = null;
        this.wasmMemory = null;
        this.wasmReady = false;
        this.sampleRate = options.processorOptions?.sampleRate || sampleRate;
        
        // Buffer pointers in WASM memory
        this.inputPtr = 0;
        this.outputPtr = 0;
        this.bufferSize = 128;
        
        // Message handling
        this.port.onmessage = (e) => this.handleMessage(e.data);
        
        // Initialize WASM
        this.initWasm();
    }
    
    async initWasm() {
        try {
            // Decode base64 WASM
            const wasmBinary = Uint8Array.from(atob(WASM_BASE64), c => c.charCodeAt(0));
            
            // Compile WASM module
            this.wasmModule = await WebAssembly.compile(wasmBinary);
            
            // Create memory
            this.wasmMemory = new WebAssembly.Memory({ initial: 16, maximum: 16 });
            
            // Create import object
            const importObject = {
                env: {
                    memory: this.wasmMemory,
                },
                a: {
                    // Emscripten runtime stubs
                    b: (code, sigPtr, argbuf) => 0,  // emscripten_asm_const_int
                    a: (requestedSize) => { throw new Error('OOM'); },  // emscripten_resize_heap
                },
            };
            
            // Instantiate
            this.wasmInstance = await WebAssembly.instantiate(this.wasmModule, importObject);
            
            // Get memory from exports if available
            if (this.wasmInstance.exports.c) {
                this.wasmMemory = this.wasmInstance.exports.c;
            }
            
            // Initialize
            if (this.wasmInstance.exports.e) {
                this.wasmInstance.exports.e();  // umi_sim_init
            } else if (this.wasmInstance.exports.ec) {
                this.wasmInstance.exports.ec(); // umi_create
            }
            
            // Allocate I/O buffers
            this.allocateBuffers();
            
            this.wasmReady = true;
            this.port.postMessage({ type: 'ready' });
            
        } catch (err) {
            console.error('[UmiSynthSimProcessor] WASM init failed:', err);
            this.port.postMessage({ type: 'error', message: err.message });
        }
    }
    
    allocateBuffers() {
        // Use malloc if available, otherwise use fixed region
        const exports = this.wasmInstance.exports;
        if (exports.zc) {  // malloc
            this.inputPtr = exports.zc(this.bufferSize * 4);
            this.outputPtr = exports.zc(this.bufferSize * 4);
        } else {
            // Fallback: use fixed region after 64KB
            const heapBase = 65536;
            this.inputPtr = heapBase;
            this.outputPtr = heapBase + this.bufferSize * 4;
        }
    }
    
    handleMessage(msg) {
        if (!this.wasmReady) return;
        
        const exports = this.wasmInstance.exports;
        
        switch (msg.type) {
            case 'note-on':
                if (exports.h) exports.h(msg.note, msg.velocity);      // umi_sim_note_on
                else if (exports.hc) exports.hc(msg.note, msg.velocity); // umi_note_on
                break;
                
            case 'note-off':
                if (exports.i) exports.i(msg.note);      // umi_sim_note_off
                else if (exports.ic) exports.ic(msg.note); // umi_note_off
                break;
                
            case 'cc':
                if (exports.j) exports.j(msg.cc, msg.value);  // umi_sim_cc
                break;
                
            case 'midi':
                if (exports.k) exports.k(msg.status, msg.data1, msg.data2);  // umi_sim_midi
                break;
                
            case 'set-param':
                if (exports.q) exports.q(msg.id, msg.value);      // umi_sim_set_param
                else if (exports.pc) exports.pc(msg.id, msg.value); // umi_set_param
                break;
                
            case 'reset':
                if (exports.f) exports.f();       // umi_sim_reset
                else if (exports.Ba) exports.Ba(); // umi_kernel_reset
                break;
                
            case 'get-kernel-state':
                this.sendKernelState();
                break;
        }
    }
    
    sendKernelState() {
        if (!this.wasmReady) return;
        
        const exports = this.wasmInstance.exports;
        const UTF8ToString = (ptr) => {
            if (!ptr) return '';
            const heap = new Uint8Array(this.wasmMemory.buffer);
            let str = '';
            let i = ptr;
            while (heap[i] !== 0 && i < heap.length) {
                str += String.fromCharCode(heap[i++]);
            }
            return str;
        };
        
        // Build kernel state from exported functions
        const state = {
            type: 'kernel-state',
            uptime: (exports.z ? exports.z() : 0) + (exports.A ? exports.A() * 0x100000000 : 0),
            audioBuffers: exports.E ? exports.E() : 0,
            audioDrops: exports.F ? exports.F() : 0,
            dspLoad: exports.G ? exports.G() : 0,
            dspPeak: exports.H ? exports.H() : 0,
            audioRunning: exports.J ? exports.J() !== 0 : false,
            midiRx: exports.K ? exports.K() : 0,
            midiTx: exports.L ? exports.L() : 0,
            batteryPercent: exports.M ? exports.M() : 100,
            batteryCharging: exports.N ? exports.N() !== 0 : false,
            usbConnected: exports.O ? exports.O() !== 0 : true,
            taskCount: exports.W ? exports.W() : 0,
            taskReady: exports.X ? exports.X() : 0,
            taskBlocked: exports.Y ? exports.Y() : 0,
            contextSwitches: exports.Z ? exports.Z() : 0,
            heapUsed: exports.ha ? exports.ha() : 0,
            heapTotal: exports.ia ? exports.ia() : 0,
            heapPeak: exports.ja ? exports.ja() : 0,
            stackUsed: exports.ka ? exports.ka() : 0,
            stackTotal: exports.la ? exports.la() : 0,
        };
        
        this.port.postMessage(state);
    }
    
    process(inputs, outputs, parameters) {
        const output = outputs[0];
        if (!output || output.length === 0) return true;
        
        const frames = output[0].length;
        
        if (!this.wasmReady) {
            // Output silence while initializing
            for (const channel of output) {
                channel.fill(0);
            }
            return true;
        }
        
        try {
            const exports = this.wasmInstance.exports;
            const heap = new Float32Array(this.wasmMemory.buffer);
            
            // Get input (if available)
            const input = inputs[0];
            if (input && input[0]) {
                heap.set(input[0], this.inputPtr / 4);
            }
            
            // Call process function
            if (exports.g) {
                // umi_sim_process(input, output, frames, sampleRate)
                exports.g(this.inputPtr, this.outputPtr, frames, Math.round(this.sampleRate));
            } else if (exports.gc) {
                // umi_process(input, output, frames, sampleRate)
                exports.gc(this.inputPtr, this.outputPtr, frames, Math.round(this.sampleRate));
            }
            
            // Copy output from WASM memory
            const outputStart = this.outputPtr / 4;
            for (const channel of output) {
                channel.set(heap.subarray(outputStart, outputStart + frames));
            }
            
        } catch (err) {
            console.error('[UmiSynthSimProcessor] Process error:', err);
            for (const channel of output) {
                channel.fill(0);
            }
        }
        
        return true;
    }
}

registerProcessor('umi-synth-sim-processor', UmiSynthSimProcessor);
